// websim-selector.js — device + project switcher for the websim shells.
//
// Populated from /projects.json, which is generated by websim/gen_manifest.py and
// served at the co-serve root by `make websim-all`. Picking a project navigates to
// that project's prebuilt page, so the whole UI (correct shell + that unit's
// parameter sliders) is rebuilt on load — "reload the components as required".
//
// When a single project is served standalone (`make wasm`), there is no manifest,
// so /projects.json 404s and the selector hides itself: the page looks unchanged.
(function () {
  "use strict";

  // "/nts-1_mkii/waves/waves.html" -> "nts-1_mkii/waves/waves.html"
  function currentPagePath() {
    return decodeURIComponent(window.location.pathname).replace(/^\/+/, "");
  }

  function option(value, text) {
    var o = document.createElement("option");
    o.value = value;
    o.textContent = text;
    return o;
  }

  function init(manifest) {
    var devices = (manifest && manifest.devices) || [];
    var container = document.getElementById("WebsimSelector");
    var deviceSelect = document.getElementById("DeviceSelect");
    var projectSelect = document.getElementById("ProjectSelect");

    if (!container || !deviceSelect || !projectSelect || devices.length === 0) {
      if (container) container.style.display = "none";
      return;
    }

    var here = currentPagePath();

    // Which device owns the page we're currently on (default: first device).
    var currentDeviceId = devices[0].id;
    devices.forEach(function (d) {
      d.projects.forEach(function (p) {
        if (p.page === here) currentDeviceId = d.id;
      });
    });

    function deviceById(id) {
      return devices.filter(function (d) { return d.id === id; })[0] || devices[0];
    }

    function fillProjects(deviceId, selectedPage) {
      projectSelect.innerHTML = "";
      var d = deviceById(deviceId);
      d.projects.forEach(function (p) {
        projectSelect.appendChild(option(p.page, p.name));
      });
      if (selectedPage) projectSelect.value = selectedPage;
      if (!projectSelect.value && d.projects.length) {
        projectSelect.value = d.projects[0].page;
      }
    }

    function navigateTo(page) {
      if (page && page !== here) window.location.href = "/" + page;
    }

    devices.forEach(function (d) {
      deviceSelect.appendChild(option(d.id, d.name));
    });
    deviceSelect.value = currentDeviceId;
    fillProjects(currentDeviceId, here);

    // Changing device repopulates the project list and loads that device's first
    // project; changing project loads it. Re-selecting the current page is a no-op.
    deviceSelect.onchange = function () {
      fillProjects(deviceSelect.value, null);
      navigateTo(projectSelect.value);
    };
    projectSelect.onchange = function () {
      navigateTo(projectSelect.value);
    };

    container.style.display = ""; // reveal (class .control -> display:flex)
  }

  document.addEventListener("DOMContentLoaded", function () {
    fetch("/projects.json", { cache: "no-store" })
      .then(function (r) { return r.ok ? r.json() : null; })
      .then(init)
      .catch(function () {
        var c = document.getElementById("WebsimSelector");
        if (c) c.style.display = "none";
      });
  });
})();
